const MEDELLIN_ZONAS = {
  type: 'FeatureCollection',
  features: MEDELLIN_COMUNAS_CENTROS.map(c => ({
    type: 'Feature',
    properties: { nombre: c.nombre, comuna_id: c.id, tipo: 'comuna' },
    geometry: { type: 'Polygon', coordinates: [hexAround(c.lat, c.lng, 0.012)] },
  })),
};

function pointInRing(pt, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > pt[1]) !== (yj > pt[1])) &&
      (pt[0] < (xj - xi) * (pt[1] - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}

function pointInFeature(lat, lng, feature) {
  const geom = feature.geometry;
  if (!geom) return false;
  const pt = [lng, lat];
  if (geom.type === 'Polygon') {
    if (!pointInRing(pt, geom.coordinates[0])) return false;
    for (let k = 1; k < geom.coordinates.length; k++) {
      if (pointInRing(pt, geom.coordinates[k])) return false; // hueco
    }
    return true;
  }
  if (geom.type === 'MultiPolygon') {
    return geom.coordinates.some(poly => {
      if (!pointInRing(pt, poly[0])) return false;
      for (let k = 1; k < poly.length; k++) if (pointInRing(pt, poly[k])) return false;
      return true;
    });
  }
  return false;
}

function findDeptForPoint(lat, lng) {
  for (const f of DEPT_BOUNDARIES.features) {
    if (pointInFeature(lat, lng, f)) return f.properties.nombre;
  }
  return null;
}

function findComunaForPoint(lat, lng) {
  for (const f of MEDELLIN_ZONAS.features) {
    if (pointInFeature(lat, lng, f)) return f.properties.nombre;
  }
  return null;
}

window.DEPT_BOUNDARIES = DEPT_BOUNDARIES;
window.MEDELLIN_ZONAS = MEDELLIN_ZONAS;
window.findDeptForPoint = findDeptForPoint;
window.findComunaForPoint = findComunaForPoint;